/// Async buffered read
pub trait AsyncBufRead: AsyncRead {
    /// Fill internal buffer and return reference
    fn poll_fill_buf(
        self: Pin<&mut Self>,
        cx: &mut Context<'_>,
    ) -> Poll<io::Result<&[u8]>>;

    /// Consume n bytes from buffer
    fn consume(self: Pin<&mut Self>, amt: usize);
